settings.cus_css:
.rectifaction_non_compliance_second.image_text_section .image-text-heading{max-width:100%;}

.rectifaction_non_compliance_second.image_text_section .image-text-block {flex-direction: row-reverse;}

@media screen and (min-width:992px){
.rectifaction_non_compliance_second .image_text_right ul{padding-left:0;padding-right:2rem;}
}

.rectifaction_non_compliance_second.image_text_section .image-text-block{align-items: center;}

.rectifaction_non_compliance_second.image_text_section .image_text_right {font-size: 16px;line-height: 22px;}

.rectifaction_non_compliance_second.image_text_section .image_text_right ul li:after{top:7px;}

@media screen and (max-width:575px){
.rectifaction_non_compliance_second.image_text_section .image_text_right {font-size: 14px;}
}

settings.css:
.compliance-analysis_richtext .rich-text__text{text-align:left}
.compliance-analysis_richtext .rich-text__heading{color: #193e92;font-size:24px;
text-align: left;}
.compliance-analysis_richtext .rich-text__blocks{max-width:140rem;}

